-- Example: create a composite covering index and query it
CREATE INDEX idx_orders_user_created_status ON orders(user_id, created_at DESC, status);

-- Query benefits from index-only scan if it selects only index columns
SELECT status, created_at FROM orders WHERE user_id = 123 ORDER BY created_at DESC LIMIT 10;

-- Check plan
EXPLAIN ANALYZE SELECT status, created_at FROM orders WHERE user_id = 123 ORDER BY created_at DESC LIMIT 10;
